---@class LGoodsBubble:LBubbleBase
local LGoodsBubble = LxClass("LGoodsBubble", LBubbleBase)
local typeOfTextMesh = typeof(CS.TextMeshPro)
local BuildingClick = CS.BuildingClick
local Tweening = DG.Tweening


function LGoodsBubble:LGoodsBubble()
    self._seqCom = SequenceCom:New()
end

function LGoodsBubble:GetPrefabPath()
    return "UI/Prefabs/Com/GoodsBubble","UI/Prefabs/Com","GoodsBubble"
end

function LGoodsBubble:OnSetBubbleContent(item,itemdata)
    local trans =CS.FindTrans(item,"bubble")
    self:SetSprite(item,trans,itemdata.bgPath)
    trans = CS.FindTrans(item,"bubble/tag")
    self:SetSprite(item,trans,itemdata.tagPath)
    trans = CS.FindTrans(item,"bubble/icon")
    self:SetSprite(item,trans,itemdata.itemIcon)


    self:SetFollow(itemdata.followTran,itemdata.offset)
    local img = CS.FindTrans(item,"bubble")
    local comp = BuildingClick.Get(img.gameObject)
    if comp then
        comp.ClickDelegate = itemdata.callBack
    end

    local seq = self._seqCom:CreateSeq("scale")
    item.localScale = Vector3.one
    local tween = item:DOScale(Vector3.one*0.9,1)
    seq:Append(tween)
    seq:SetLoops(-1,Tweening.LoopType.Yoyo)
    seq:PlayForward()
end


return LGoodsBubble